/**
 * @param {Context} context
 * @description Sets the requirement of the field. The method must return true or false
*/
const SetRequired = async (context) => {
    // Check if user is NOT in Admin OR is NOT in MAROMA
    // This means anyone not in either group will need to fill this field
    const userPermissions = !IsInGroup("Admin") && !IsInGroup("MAROMA");

    // Get installation status
    const installationStatus = context?.Form?.Page1?.InstallationStatus?.Value || "";

    // Valid statuses that require the field
    const requiredStatuses = [
        "Installed", 
        "Ready for Review", 
        "Completed & Submitted", 
        "Invoiced"
    ];

    // Field is required if user is not in privileged groups AND status is in the required list
    return userPermissions && requiredStatuses.includes(installationStatus);
}

/**
 * @param {Context} context
 * @description Sets the requirement of the field. The method must return true or false
 */
const SetRequired = async (context) => {
    const projectStage = context?.Form?.Page1?.ProjectStage?.Value || "";
    const invoiceTrue = !!context?.Form?.ContractorInformationPage?.InvoiceInstallation?.Value;
    const documentation = context?.Form?.Page2?.ApplicableDocumentation?.Value || "";

    if (IsInGroup("MAROMA")) {
        return false;
    }
    // If Minor Home Repair is selected, field is never required (override)
    if (documentation?.includes("AHRI Certificate")) {
        return false;
    }

    // Field is required when both conditions are met
    if (projectStage === "Installation" && invoiceTrue) {
        return true;
    }

    // Not required in all other cases
    return false;
};

