{"Configuration":"/** @param {Context} context */
const SetValue = async (context) => {
    const assignedDate = context?.Form?.Page1?.LeadAssignedDate?.Value || "";
    const projectStage = context?.Form?.Page1?.ProjectStage?.Value || "";
    const installationCompletedDate = context?.Form?.Page1?.InstallationCompletedDate?.Value || "";

    // Return N/A if no assigned date
    if (!assignedDate) {
        return "N/A";
    }

    // Calculate estimated date (+60 days)
    const estimatedDate = new Date(assignedDate);
    estimatedDate.setDate(estimatedDate.getDate() + 60);
    const formattedEstDate = `${estimatedDate.getMonth() + 1}/${estimatedDate.getDate()}/${estimatedDate.getFullYear()}`;

    // Add difference if project is completed
    if (projectStage === "Completed" && installationCompletedDate) {
        const completedDate = new Date(installationCompletedDate);
        const diffDays = Math.round((completedDate - estimatedDate) / (1000 * 60 * 60 * 24));
        return `${formattedEstDate} (${diffDays > 0 ? "+" : ""}${diffDays} days)`;
    }

    return formattedEstDate;
};","ClearValueOnTrue":false,"ClearValueOnFalse":false,"Key":null,"Fields":[{"ModelKey":"Form.Page1.ProjectStage","FieldName":"ProjectStage","IsSystemModelKey":false},{"ModelKey":"Form.Page1.LeadAssignedDate","FieldName":"LeadAssignedDate","IsSystemModelKey":false},{"ModelKey":"Form.Page1.InstallationCompletedDate","FieldName":"InstallationCompletedDate","IsSystemModelKey":false}]}

{"Configuration":"/** @param {Context} context */
const SetValue = async (context) => {
    // Extract values
    const assignedDate = context?.Form?.Page1?.LeadAssignedDate?.Value || "";
    const projectStage = context?.Form?.Page1?.ProjectStage?.Value || "";
    const leadStatus = context?.Form?.Page1?.LeadStatuses?.Value || "";

    // Return early if conditions aren't met
    if (projectStage === "Lead" || leadStatus !== "Completed Lead" || 
        !assignedDate || projectStage === "Completed") {
        return "N/A";
    }

    // Calculate target date (60 days after assigned date)
    const targetDate = new Date(assignedDate);
    targetDate.setDate(targetDate.getDate() + 60);

    // Calculate days remaining
    const currentDate = new Date();
    const daysLeft = Math.ceil((targetDate - currentDate) / (1000 * 60 * 60 * 24));

    return `${daysLeft} day(s)`;
};","ClearValueOnTrue":false,"ClearValueOnFalse":false,"Key":null,"Fields":[{"ModelKey":"Form.Page1.ProjectStage","FieldName":"ProjectStage","IsSystemModelKey":false},{"ModelKey":"Form.Page1.LeadStatuses","FieldName":"LeadStatuses","IsSystemModelKey":false},{"ModelKey":"Form.Page1.LeadAssignedDate","FieldName":"LeadAssignedDate","IsSystemModelKey":false}]}

