/**
 * @param {Context} context
 * @description Sets if the field is enabled. The method must return true or false
 */
const SetEnabled = async (context) => {
    const projectStage = context?.Form?.Page1?.ProjectStage?.Value || "";
    const installation = context?.Form?.Page1?.InstallationStatus?.Value || "";
    const assessment = context?.Form?.Page1?.AssessmentStatus?.Value || "";
    const enrollment = context?.Form?.Page1?.EnrollmentStatus?.Value || "";

    if (IsInGroup("Admin")) {
        return true;
    }

    // Check installation status first - these always enable the field
    if (installation == "Installed" || 
        installation == "Post Installation Review" || 
        installation == "Canceled Installation") {
        return true;
    }

    // Check assessment stage conditions
    if (projectStage == "Assessment") {
        const assessmentFailureStates = [
            "Installation requires excessive remediation",
            "Customer Refused to Participate", 
            "Canceled",
            "Customer does not meet minimum savings requirement"
        ];

        if (assessmentFailureStates.includes(assessment)) {
            return true;
        }
    }

    // Check enrollment stage conditions
    if (projectStage == "Enrollment") {
        // Enable if enrollment has any status except empty string or "In Progress"
        if (enrollment !== "" && enrollment !== "In Progress") {
            return true;
        }
    }


    // Default case - field is disabled
    return false;
};

